// Extract search parameters
const body = $input.first().json.body;
const { query, topK = 5, threshold = 0.30, workspaceId, documentId } = body;

if (!query || !workspaceId) {
  throw new Error('query and workspaceId are required');
}

return [{
  json: {
    query,
    topK: Math.min(20, Math.max(1, parseInt(String(topK)) || 5)),
    threshold: Math.max(0, Math.min(1, parseFloat(String(threshold)) || 0.30)),
    workspaceId,
    documentId: documentId || null
  }
}];

// Format search results
const results = $input.all();
const input = $('Extract Input').item.json;

const formattedResults = results.map(r => ({
  id: r.json.id,
  content: r.json.content,
  chunkIndex: r.json.chunk_index,
  similarity: r.json.similarity,
  document: {
    id: r.json.document_id,
    title: r.json.document_title,
    fileType: 'unknown'
  },
  chunkType: r.json.chunk_type || 'text',
  ocrText: r.json.ocr_text || null,
  caption: r.json.caption || null,
  imageSummary: r.json.image_summary || null,
  imageUrl: r.json.image_url || null
}));

const topSimilarityScore = formattedResults.length > 0 ? formattedResults[0].similarity : null;

return [{
  json: {
    results: formattedResults,
    metrics: {
      query: input.query,
      topK: input.topK,
      threshold: input.threshold,
      resultCount: formattedResults.length,
      topSimilarityScore,
      searchMode: 'vector'
    }
  }
}];
